import{_ as l,C as r,o as s,c as n,a2 as _,E as a,w as e,a as i}from"./chunks/framework.C24VBsJ9.js";const P=JSON.parse('{"title":"蜂鸣器驱动 - GPIO 极性配置实战","description":"","frontmatter":{},"headers":[],"relativePath":"tutorial/driver/04_beep_driver/01_introduction.md","filePath":"tutorial/driver/04_beep_driver/01_introduction.md","lastUpdated":1779887266000}'),c={name:"tutorial/driver/04_beep_driver/01_introduction.md"};function p(h,t,u,m,b,f){const o=r("ChapterLink"),d=r("ChapterNav");return s(),n("div",null,[t[2]||(t[2]=_('<h1 id="蜂鸣器驱动-gpio-极性配置实战" tabindex="-1">蜂鸣器驱动 - GPIO 极性配置实战 <a class="header-anchor" href="#蜂鸣器驱动-gpio-极性配置实战" aria-label="Permalink to &quot;蜂鸣器驱动 - GPIO 极性配置实战&quot;">​</a></h1><h2 id="前言-从-led-到蜂鸣器" tabindex="-1">前言：从 LED 到蜂鸣器 <a class="header-anchor" href="#前言-从-led-到蜂鸣器" aria-label="Permalink to &quot;前言：从 LED 到蜂鸣器&quot;">​</a></h2><p>在 LED 驱动教程中，我们学习了 Platform 框架和 HAL 层设计。对于蜂鸣器驱动，Platform 框架部分你已经掌握了——它和 LED 驱动几乎一样。</p><p>蜂鸣器驱动的真正价值在于：<strong>它暴露了一个常见的问题——GPIO 极性配置错误</strong>。这是新手最容易踩的坑，也是本教程的核心内容。</p><div class="tip custom-block"><p class="custom-block-title">教学目标</p><p>通过蜂鸣器驱动，深入理解 GPIO 极性配置，掌握 <code>devm_gpiod_get()</code> 的 flags 参数和 <code>gpiod_set_value()</code> 的极性反转逻辑。</p></div><h2 id="和-led-驱动的异同" tabindex="-1">和 LED 驱动的异同 <a class="header-anchor" href="#和-led-驱动的异同" aria-label="Permalink to &quot;和 LED 驱动的异同&quot;">​</a></h2><h3 id="相同点" tabindex="-1">相同点 <a class="header-anchor" href="#相同点" aria-label="Permalink to &quot;相同点&quot;">​</a></h3><ul><li>都是 Platform 框架驱动</li><li>都用 <code>devm_gpiod_get()</code> 获取 GPIO</li><li>都用 <code>gpiod_set_value()</code> 控制状态</li><li>都通过字符设备暴露给用户空间</li></ul><h3 id="不同点" tabindex="-1">不同点 <a class="header-anchor" href="#不同点" aria-label="Permalink to &quot;不同点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>LED 驱动</th><th>蜂鸣器驱动</th></tr></thead><tbody><tr><td>HAL 层</td><td>有（led_hw.c/h）</td><td>无（直接操作 GPIO）</td></tr><tr><td>初始状态</td><td>无所谓</td><td>必须静音</td></tr><tr><td>极性问题</td><td>相对简单</td><td>暴露经典坑</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">为什么蜂鸣器需要关注初始状态</p><p>如果驱动加载后蜂鸣器一直响，用户体验很差，还可能让人以为板子坏了。蜂鸣器驱动必须确保<strong>默认静音</strong>。</p></div><h2 id="教程结构" tabindex="-1">教程结构 <a class="header-anchor" href="#教程结构" aria-label="Permalink to &quot;教程结构&quot;">​</a></h2><p>本教程简化为四个章节，专注于 GPIO 极性配置：</p><ol><li><strong><a href="./02_gpio_polarity">02_gpio_polarity</a></strong> - GPIO 极性配置详解（核心）</li><li><strong><a href="./03_driver_impl">03_driver_impl</a></strong> - 驱动实现分析</li><li><strong><a href="./04_build_and_test">04_build_and_test</a></strong> - 编译测试与调试</li></ol><div class="tip custom-block"><p class="custom-block-title">前置知识</p><ul><li>Platform 驱动框架（在 03_platform_led_driver 中已讲解）</li><li>字符设备基础（<code>file_operations</code>、<code>cdev</code>）</li><li>设备树基本语法</li></ul></div><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>本节介绍了蜂鸣器驱动的基本情况。接下来我们直接进入 GPIO 极性配置的详细分析，这是本教程的核心内容。</p><hr>',18)),a(d,{variant:"sub"},{default:e(()=>[a(o,{href:"../03_platform_led_driver/",variant:"sub"},{default:e(()=>[...t[0]||(t[0]=[i("← Platform LED 驱动",-1)])]),_:1}),a(o,{href:"02_gpio_polarity.md",variant:"sub"},{default:e(()=>[...t[1]||(t[1]=[i("GPIO 极性配置 →",-1)])]),_:1})]),_:1})])}const g=l(c,[["render",p]]);export{P as __pageData,g as default};
